// Parse AI brief
const aiResponse = $input.first().json.content;
let brief;

try {
  brief = JSON.parse(aiResponse);
} catch (e) {
  brief = {
    summary: 'Incident requires attention',
    key_facts: ['System affected', 'Impact unknown', 'Team notified'],
    options: [
      { label: 'Investigate', action: 'investigate', pros: 'Quick response', cons: 'May need escalation' },
      { label: 'Escalate', action: 'escalate', pros: 'Expert handling', cons: 'Longer response time' },
      { label: 'Monitor', action: 'monitor', pros: 'No disruption', cons: 'Risk of escalation' }
    ],
    recommended: 'Investigate'
  };
}

const incident = $input.all()[0].json;
const team = $input.all()[1]?.json || [];

return [{
  json: {
    alert_id: 'CEO-' + Date.now(),
    incident_type: incident.incident_type,
    severity: incident.severity,
    summary: brief.summary,
    key_facts: brief.key_facts,
    action_options: brief.options,
    recommended_action: brief.recommended,
    one_tap_commands: {
      '1': brief.options[0]?.action || 'investigate',
      '2': brief.options[1]?.action || 'escalate',
      '3': brief.options[2]?.action || 'monitor'
    },
    team_available: team.length,
    audit_log_id: 'AUDIT-' + Date.now(),
    timestamp: new Date().toISOString()
  }
}];

